import os
import secrets
import pyotp
from flask import Flask, request, jsonify, session, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = os.urandom(24)
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(minutes=30)

users_db = {
    'user1': {
        'password_hash': generate_password_hash('password123'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    }
}

sessions_db = {}


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        return f(*args, **kwargs)
    return decorated_function


def mfa_verified_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        
        user_id = session['user_id']
        if user_id not in users_db or not users_db[user_id].get('mfa_verified', False):
            return jsonify({'error': 'MFA verification required'}), 403
        
        return f(*args, **kwargs)
    return decorated_function


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username in users_db:
        return jsonify({'error': 'User already exists'}), 400
    
    mfa_secret = pyotp.random_base32()
    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_secret': mfa_secret,
        'mfa_verified': False
    }
    
    totp = pyotp.TOTP(mfa_secret)
    provisioning_uri = totp.provisioning_uri(name=username, issuer_name='FlaskApp')
    
    return jsonify({
        'message': 'User registered successfully',
        'mfa_secret': mfa_secret,
        'provisioning_uri': provisioning_uri
    }), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session['user_id'] = username
    session['password_verified'] = True
    session['mfa_verified'] = False
    session.permanent = True
    
    session_token = secrets.token_urlsafe(32)
    sessions_db[session_token] = {
        'user_id': username,
        'password_verified': True,
        'mfa_verified': False,
        'created_at': datetime.utcnow()
    }
    
    return jsonify({
        'message': 'Password verified successfully',
        'redirect': '/verify-mfa',
        'session_token': session_token,
        'access_level': 'partial'
    }), 200


@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    if 'user_id' not in session:
        return jsonify({'error': 'Please login first'}), 401
    
    data = request.get_json()
    mfa_code = data.get('mfa_code')
    
    if not mfa_code:
        return jsonify({'error': 'MFA code required'}), 400
    
    user_id = session['user_id']
    user = users_db.get(user_id)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(mfa_code, valid_window=1):
        session['mfa_verified'] = True
        users_db[user_id]['mfa_verified'] = True
        
        for token, sess_data in sessions_db.items():
            if sess_data['user_id'] == user_id:
                sess_data['mfa_verified'] = True
        
        return jsonify({
            'message': 'MFA verified successfully',
            'access_level': 'full'
        }), 200
    else:
        return jsonify({'error': 'Invalid MFA code'}), 401


@app.route('/protected-resource', methods=['GET'])
@login_required
def protected_resource():
    user_id = session['user_id']
    mfa_verified = session.get('mfa_verified', False)
    
    return jsonify({
        'message': 'Access granted to protected resource',
        'user': user_id,
        'mfa_verified': mfa_verified,
        'access_level': 'full' if mfa_verified else 'partial',
        'data': 'This is accessible after password verification'
    }), 200


@app.route('/sensitive-resource', methods=['GET'])
@mfa_verified_required
def sensitive_resource():
    user_id = session['user_id']
    
    return jsonify({
        'message': 'Access granted to sensitive resource',
        'user': user_id,
        'access_level': 'full',
        'data': 'This requires full MFA verification'
    }), 200


@app.route('/mfa-status', methods=['GET'])
@login_required
def mfa_status():
    user_id = session['user_id']
    mfa_verified = session.get('mfa_verified', False)
    
    return jsonify({
        'user': user_id,
        'mfa_verified': mfa_verified,
        'password_verified': session.get('password_verified', False)
    }), 200


@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200


if __name__ == '__main__':
    app.run(debug=True, port=5000)